arguments.file_text:
@inject CascadingValueSource<ThemeInfo> ThemeSource

<span class="theme-indicator" style="color: @Theme?.AccentColor" title="Current theme">
    @switch (Theme?.Mode)
    {
        case ThemeMode.Dark:
            <span>🌙 Dark</span>
            break;
        case ThemeMode.System:
            <span>💻 System</span>
            break;
        default:
            <span>☀️ Light</span>
            break;
    }
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 400px; border-color: @Theme?.AccentColor;">
    <h4>Theme</h4>
    <div class="btn-group mb-3" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            var isActive = Theme?.Mode == mode;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetMode(mode)">
                @mode
            </button>
        }
    </div>

    <h4>Accent Color</h4>
    <input type="color"
           class="form-control form-control-color mb-3"
           value="@(Theme?.AccentColor ?? "#0d6efd")"
           @onchange="SetAccentColor" />

    <p class="text-muted mb-0" style="color: @Theme?.AccentColor !important;">
        Preview: This text uses your accent color.
    </p>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task SetMode(ThemeMode mode)
    {
        var updated = Theme! with { Mode = mode };
        await ThemeSource.NotifyChangedAsync(updated);
    }

    private async Task SetAccentColor(ChangeEventArgs e)
    {
        var updated = Theme! with { AccentColor = e.Value?.ToString() ?? "#0d6efd" };
        await ThemeSource.NotifyChangedAsync(updated);
    }
}

